  1→import type {
  2→  DedupCandidate,
  3→  DedupCheckResult,
  4→  ProjectedPoint,
  5→  SubmissionCategory,
  6→  SubmissionDetails,
  7→  SubmissionLocation,
  8→} from "../../shared/types.js";
  9→import { haversineKm } from "./submissionFraud.js";
 10→
 11→export const DEDUP_RADIUS_METERS = 25;
 12→export const DEDUP_RADIUS_ROAD_METERS = 50;
 13→
 14→const MAX_CANDIDATES = 5;
 15→const NAME_SIMILARITY_PROMPT_THRESHOLD = 0.7;
 16→const STRICT_DISTANCE_PROMPT_METERS = 25;
 17→const VERY_CLOSE_DISTANCE_PROMPT_METERS = 8;
 18→const HIGH_MATCH_SCORE_PROMPT_THRESHOLD = 0.85;
 19→
 20→function dedupRadiusMeters(category: SubmissionCategory): number {
 21→  return category === "transport_road" ? DEDUP_RADIUS_ROAD_METERS : DEDUP_RADIUS_METERS;
 22→}
 23→
 24→function normalizeName(input: unknown): string {
 25→  if (typeof input !== "string") return "";
 26→  return input
 27→    .normalize("NFKD")
 28→    .replace(/[\u0300-\u036f]/g, "")
 29→    .toLowerCase()
 30→    .replace(/[^a-z0-9\s]/g, " ")
 31→    .replace(/\s+/g, " ")
 32→    .trim();
 33→}
 34→
 35→function detailsName(details: SubmissionDetails): string {
 36→  return (
 37→    normalizeName(details.siteName) ||
 38→    normalizeName(details.name) ||
 39→    normalizeName(details.roadName) ||
 40→    normalizeName(details.brand)
 41→  );
 42→}
 43→
 44→function pointName(point: ProjectedPoint): string {
 45→  const details = point.details ?? {};
 46→  return (
 47→    normalizeName(details.siteName) ||
 48→    normalizeName(details.name) ||
 49→    normalizeName(details.roadName) ||
 50→    normalizeName(details.brand)
 51→  );
 52→}
 53→
 54→function levenshteinDistance(a: string, b: string): number {
 55→  if (a === b) return 0;
 56→  if (!a.length) return b.length;
 57→  if (!b.length) return a.length;
 58→  const prev = new Array<number>(b.length + 1);
 59→  const curr = new Array<number>(b.length + 1);
 60→  for (let j = 0; j <= b.length; j += 1) prev[j] = j;
 61→  for (let i = 1; i <= a.length; i += 1) {
 62→    curr[0] = i;
 63→    for (let j = 1; j <= b.length; j += 1) {
 64→      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
 65→      curr[j] = Math.min(
 66→        curr[j - 1] + 1,
 67→        prev[j] + 1,
 68→        prev[j - 1] + cost,
 69→      );
 70→    }
 71→    for (let j = 0; j <= b.length; j += 1) prev[j] = curr[j];
 72→  }
 73→  return prev[b.length];
 74→}
 75→
 76→function similarityScore(sourceName: string, candidateName: string): number {
 77→  if (!sourceName && !candidateName) return 0.5;
 78→  if (!sourceName || !candidateName) return 0.35;
 79→  const distance = levenshteinDistance(sourceName, candidateName);
 80→  const maxLen = Math.max(sourceName.length, candidateName.length);
 81→  return Math.max(0, Math.min(1, 1 - distance / maxLen));
 82→}
 83→
 84→function displayName(point: ProjectedPoint): string | null {
 85→  const details = point.details ?? {};
 86→  const raw =
 87→    (typeof details.siteName === "string" && details.siteName.trim()) ||
 88→    (typeof details.name === "string" && details.name.trim()) ||
 89→    (typeof details.roadName === "string" && details.roadName.trim()) ||
 90→    null;
 91→  return raw;
 92→}
 93→
 94→export function buildDedupCandidates(
 95→  category: SubmissionCategory,
 96→  location: SubmissionLocation,
 97→  incomingDetails: SubmissionDetails,
 98→  points: ProjectedPoint[],
 99→): DedupCheckResult {
100→  const radiusMeters = dedupRadiusMeters(category);
101→  const sourceName = detailsName(incomingDetails);
102→  const candidates: DedupCandidate[] = points
103→    .filter((point) => point.category === category)
104→    .map((point) => {
105→      const distanceMeters = haversineKm(location, point.location) * 1000;
106→      const candidateName = pointName(point);
107→      const nameScore = similarityScore(sourceName, candidateName);
108→      const distanceScore = Math.max(0, 1 - distanceMeters / radiusMeters);
109→      const matchScore = Math.max(0, Math.min(1, nameScore * 0.65 + distanceScore * 0.35));
110→      return {
111→        pointId: point.pointId,
112→        category: point.category,
113→        siteName: displayName(point),
114→        latitude: point.location.latitude,
115→        longitude: point.location.longitude,
116→        distanceMeters: Math.round(distanceMeters * 10) / 10,
117→        similarityScore: Math.round(nameScore * 1000) / 1000,
118→        matchScore: Math.round(matchScore * 1000) / 1000,
119→      };
120→    })
121→    .filter((candidate) => candidate.distanceMeters <= radiusMeters)
122→    .sort((a, b) => b.matchScore - a.matchScore || a.distanceMeters - b.distanceMeters)
123→    .slice(0, MAX_CANDIDATES);
124→
125→  const best = candidates[0];
126→  const shouldPrompt = Boolean(
127→    best && (
128→      (best.similarityScore >= NAME_SIMILARITY_PROMPT_THRESHOLD && best.distanceMeters <= STRICT_DISTANCE_PROMPT_METERS) ||
129→      best.distanceMeters <= VERY_CLOSE_DISTANCE_PROMPT_METERS ||
130→      best.matchScore >= HIGH_MATCH_SCORE_PROMPT_THRESHOLD
131→    ),
132→  );
133→
134→  return {
135→    shouldPrompt,
136→    radiusMeters,
137→    bestCandidatePointId: best?.pointId ?? null,
138→    candidates,
139→  };
140→}
