333→function metadataContext(options: ExtractPhotoMetadataOptions): string {
334→  const parts: string[] = [];
335→  const mime = normalizeString(options.mime);
336→  const ext = normalizeString(options.ext);
337→  if (mime) parts.push(`mime=${mime}`);
338→  if (ext) parts.push(`ext=${ext}`);
339→  if (typeof options.byteLength === "number" && Number.isFinite(options.byteLength) && options.byteLength > 0) {
340→    parts.push(`bytes=${Math.round(options.byteLength)}`);
341→  }
342→  return parts.join("; ");
343→}
344→
345→function withContext(reason: string, options: ExtractPhotoMetadataOptions): string {
346→  const context = metadataContext(options);
347→  if (!context) return reason;
348→  return `${reason} (${context}).`;
349→}
350→
351→function createExtractedPhotoMetadata(
352→  status: SubmissionExifStatus,
353→  reason: string | null,
354→  source: SubmissionExifSource,
355→): ExtractedPhotoMetadata {
356→  return {
357→    gps: null,
358→    capturedAt: null,
359→    deviceMake: null,
360→    deviceModel: null,
361→    exifStatus: status,
362→    exifReason: reason,
363→    exifSource: source,
364→  };
365→}
