367→async function safeParseExif(
368→  imageBuffer: Buffer,
369→  options: Parameters<typeof exifr.parse>[1],
370→): Promise<ParseAttempt> {
371→  try {
372→    const parsed = await exifr.parse(imageBuffer, options);
373→    if (!parsed || typeof parsed !== "object") return { parsed: null, error: null };
374→    return { parsed: parsed as Record<string, unknown>, error: null };
375→  } catch (error) {
376→    return { parsed: null, error: error instanceof Error ? error : new Error(String(error)) };
377→  }
378→}
379→
380→async function safeParseGps(imageBuffer: Buffer): Promise<ParseAttempt> {
381→  try {
382→    const parsed = await exifr.gps(imageBuffer);
383→    if (!parsed || typeof parsed !== "object") return { parsed: null, error: null };
384→    return { parsed: parsed as unknown as Record<string, unknown>, error: null };
385→  } catch (error) {
386→    return { parsed: null, error: error instanceof Error ? error : new Error(String(error)) };
387→  }
388→}
