390→function inferRemoteExt(photoUrl: string): string | null {
391→  try {
392→    const parsed = new URL(photoUrl);
393→    const pathname = parsed.pathname;
394→    const dotIndex = pathname.lastIndexOf(".");
395→    if (dotIndex === -1) return null;
396→    const ext = pathname.slice(dotIndex + 1).toLowerCase().trim();
397→    if (!ext || ext.length > 12) return null;
398→    return ext;
399→  } catch {
400→    return null;
401→  }
402→}
