404→export function isPhotoMetadataEffectivelyEmpty(metadata: SubmissionPhotoMetadata | null | undefined): boolean {
405→  if (!metadata) return true;
406→  return (
407→    metadata.gps === null &&
408→    metadata.capturedAt === null &&
409→    metadata.deviceMake === null &&
410→    metadata.deviceModel === null &&
411→    metadata.submissionDistanceKm === null &&
412→    metadata.submissionGpsMatch === null &&
413→    metadata.ipDistanceKm === null &&
414→    metadata.ipGpsMatch === null
415→  );
416→}
417→
418→export function isFraudCheckEffectivelyEmpty(fraudCheck: SubmissionFraudCheck | null | undefined): boolean {
419→  if (!fraudCheck) return true;
420→  return isPhotoMetadataEffectivelyEmpty(fraudCheck.primaryPhoto) && isPhotoMetadataEffectivelyEmpty(fraudCheck.secondaryPhoto);
421→}
422→
423→export function haversineKm(a: SubmissionLocation, b: SubmissionLocation): number {
424→  const toRad = (deg: number) => (deg * Math.PI) / 180;
425→  const dLat = toRad(b.latitude - a.latitude);
426→  const dLon = toRad(b.longitude - a.longitude);
427→  const lat1 = toRad(a.latitude);
428→  const lat2 = toRad(b.latitude);
429→  const sinLat = Math.sin(dLat / 2);
430→  const sinLon = Math.sin(dLon / 2);
431→  const h = sinLat * sinLat + Math.cos(lat1) * Math.cos(lat2) * sinLon * sinLon;
432→  return 2 * EARTH_RADIUS_KM * Math.atan2(Math.sqrt(h), Math.sqrt(1 - h));
433→}
434→
435→export async function extractPhotoMetadata(
436→  imageBuffer: Buffer,
437→  options: ExtractPhotoMetadataOptions = {},
438→): Promise<ExtractedPhotoMetadata> {
439→  const source: ExtractPhotoMetadataSource = options.source ?? "upload_buffer";
440→  const exifAttempt = await safeParseExif(imageBuffer, {
441→    gps: true,
442→    exif: true,
443→    tiff: true,
444→    pick: [
445→      "latitude",
446→      "longitude",
447→      "lat",
448→      "lon",
449→      "lng",
450→      "gps",
451→      "GPSLatitude",
452→      "GPSLongitude",
453→      "GPSLatitudeRef",
454→      "GPSLongitudeRef",
455→      "DateTimeOriginal",
456→      "DateTimeDigitized",
457→      "CreateDate",
458→      "ModifyDate",
459→      "Make",
460→      "Model",
461→    ],
462→  });
463→  const gpsAttempt = await safeParseGps(imageBuffer);
464→  const merged = {
465→    ...(exifAttempt.parsed ?? {}),
466→    ...(gpsAttempt.parsed ?? {}),
467→  };
468→
469→  const gps = extractGps(merged);
470→  const capturedAt =
471→    parseDateIso(merged.DateTimeOriginal) ??
472→    parseDateIso(merged.DateTimeDigitized) ??
473→    parseDateIso(merged.CreateDate) ??
474→    parseDateIso(merged.ModifyDate);
475→  const deviceMake = normalizeString(merged.Make);
476→  const deviceModel = normalizeString(merged.Model);
477→
478→  if (hasExifSignal({ gps, capturedAt, deviceMake, deviceModel })) {
479→    const exifStatus: SubmissionExifStatus = source === "remote_url" ? "fallback_recovered" : "ok";
480→    const exifReason = withContext(
481→      source === "remote_url" ? "Recovered EXIF metadata from stored photo URL" : "EXIF metadata parsed successfully",
482→      options,
483→    );
484→    return {
485→      gps,
486→      capturedAt,
487→      deviceMake,
488→      deviceModel,
489→      exifStatus,
490→      exifReason,
491→      exifSource: source,
492→    };
493→  }
494→
495→  const format = detectImageFormat(imageBuffer);
496→  const hasParseError = Boolean(exifAttempt.error || gpsAttempt.error);
497→  if (isUnsupportedExifFormat(format)) {
498→    return createExtractedPhotoMetadata(
499→      "unsupported_format",
500→      withContext(
501→        "Likely HEIC/HEIF metadata stripping or unsupported format. Enable iOS Camera Location and Most Compatible format",
502→        options,
503→      ),
504→      source,
505→    );
506→  }
507→  if (hasParseError) {
508→    return createExtractedPhotoMetadata(
509→      "parse_error",
510→      withContext("Unable to parse EXIF metadata from image bytes", options),
511→      source,
512→    );
513→  }
514→  return createExtractedPhotoMetadata(
515→    "missing",
516→    withContext(
517→      source === "remote_url" ? "No EXIF metadata found in stored photo bytes" : "No EXIF metadata found in uploaded file",
518→      options,
519→    ),
520→    source,
521→  );
522→}
