119→function toNumber(input: unknown, fallback = 0): number {
120→  if (typeof input === "number" && Number.isFinite(input)) return input;
121→  if (typeof input === "string") {
122→    const parsed = Number(input);
123→    if (Number.isFinite(parsed)) return parsed;
124→  }
125→  return fallback;
126→}
