150→function stableSort(value: unknown): unknown {
151→  if (Array.isArray(value)) return value.map(stableSort);
152→  if (!value || typeof value !== "object") return value;
153→  const entries = Object.entries(value as Record<string, unknown>)
154→    .filter(([, v]) => v !== undefined)
155→    .sort(([a], [b]) => a.localeCompare(b));
156→  const out: Record<string, unknown> = {};
157→  for (const [key, nextValue] of entries) {
158→    out[key] = stableSort(nextValue);
159→  }
160→  return out;
161→}
