202→export function computeExifTrustScore(input: {
203→  gps: SubmissionLocation | null;
204→  capturedAt: string | null;
205→  deviceMake: string | null;
206→  deviceModel: string | null;
207→  isLowEnd: boolean;
208→}): number {
209→  let score = 100;
210→  if (!input.gps) score -= 30;
211→  if (!input.capturedAt) score -= 20;
212→  if (!input.deviceMake) score -= 15;
213→  if (!input.deviceModel) score -= 15;
214→  if (input.isLowEnd && score < 50) {
215→    score = Math.min(score + 20, 50);
216→  }
217→  return Math.max(0, score);
218→}
