220→function buildRiskScore(components: RiskComponents): number {
221→  const weighted =
222→    0.25 * components.locationRisk +
223→    0.25 * components.photoRisk +
224→    0.15 * components.temporalRisk +
225→    0.20 * components.userRisk +
226→    0.15 * components.behavioralRisk;
227→  return Math.round(weighted);
228→}
