337→
338→  let priorFraudFlags = 0;
339→  try {
340→    const fraudResult = await query<{ total: number }>(
341→      `SELECT COUNT(*)::int AS total
342→       FROM fraud_audit_log
343→       WHERE user_id = $1
344→         AND action IN ('flagged', 'blocked')`,
345→      [userId],
346→    );
347→    priorFraudFlags = toInt(fraudResult.rows[0]?.total, 0);
348→  } catch (error) {
349→    if (!isMissingDbObjectError(error)) throw error;
350→  }
351→
352→  return { accountAgeDays, totalSubmissions, priorFraudFlags };
353→}
