374→function evaluateFieldPlausibility(category: SubmissionCategory, details: SubmissionDetails): { block: string | null; flags: string[] } {
375→  if (category !== "fuel_station") return { block: null, flags: [] };
376→  const flags: string[] = [];
377→
378→  const pricesByFuel = details.pricesByFuel;
379→  if (!pricesByFuel || typeof pricesByFuel !== "object") return { block: null, flags };
380→
381→  for (const [fuelTypeRaw, value] of Object.entries(pricesByFuel as Record<string, unknown>)) {
382→    const fuelType = normalizeText(fuelTypeRaw);
383→    const numeric = toNumber(value, NaN);
384→    if (!Number.isFinite(numeric)) continue;
385→    if (numeric <= 0 || numeric > 10_000) {
386→      return { block: `invalid_fuel_price_${fuelType || "unknown"}`, flags };
387→    }
388→    const range = FUEL_PRICE_RANGE_XAF[fuelType];
389→    if (!range) continue;
390→    if (numeric < range.min * 0.5 || numeric > range.max * 2) {
391→      flags.push("implausible_fuel_price");
392→    }
393→  }
394→
395→  return { block: null, flags: Array.from(new Set(flags)) };
396→}
