401→  }
402→  if (code === "velocity_limit") {
403→    return { reason: "Submission rate too high. Please wait and retry.", status: 429 };
404→  }
405→  if (code === "impossible_travel") {
406→    return { reason: "Submission blocked due to impossible travel pattern", status: 409 };
407→  }
408→  if (code === "tor_exit_ip") {
409→    return { reason: "Submission blocked from Tor exit node", status: 403 };
410→  }
411→  if (code.startsWith("invalid_fuel_price")) {
412→    return { reason: "Invalid fuel price value", status: 400 };
413→  }
414→  return { reason: "Submission blocked by fraud controls", status: 400 };
415→}
