19→export async function updateUserTrust(input: {
20→  userId: string;
21→  delta?: number;
22→  setScore?: number;
23→  suspendedUntil?: string | null;
24→  wipeRequested?: boolean;
25→}): Promise<{ trustScore: number; trustTier: TrustTier; suspendedUntil: string | null; wipeRequested: boolean }> {
26→  const current = await query<{
27→    trust_score: number | null;
28→    suspended_until: string | null;
29→    wipe_requested: boolean | null;
30→  }>(
31→    `SELECT trust_score, suspended_until, wipe_requested
32→     FROM user_profiles
33→     WHERE id = $1
34→     LIMIT 1`,
35→    [input.userId.toLowerCase().trim()],
36→  );
37→
38→  const row = current.rows[0];
39→  const nextTrustScore = normalizeTrustScore(
40→    input.setScore ?? normalizeTrustScore(row?.trust_score, DEFAULT_TRUST_SCORE) + (input.delta ?? 0),
41→  );
42→  const trustTier = getTrustTier(nextTrustScore);
43→  const suspendedUntil = input.suspendedUntil === undefined ? row?.suspended_until ?? null : input.suspendedUntil;
44→  const wipeRequested = input.wipeRequested === undefined ? row?.wipe_requested === true : input.wipeRequested;
45→
46→  await query(
47→    `UPDATE user_profiles
48→     SET trust_score = $2,
49→         trust_tier = $3,
50→         suspended_until = $4::timestamptz,
51→         wipe_requested = $5
52→     WHERE id = $1`,
53→    [input.userId.toLowerCase().trim(), nextTrustScore, trustTier, suspendedUntil, wipeRequested],
54→  );
55→
56→  return { trustScore: nextTrustScore, trustTier, suspendedUntil, wipeRequested };
