10→export async function reconcileUserProfileXp(
11→  userId: string,
12→  options: {
13→    events?: PointEvent[];
14→    profile?: UserProfile | null;
15→  } = {},
16→): Promise<UserProfile | null> {
17→  const profile = options.profile ?? (await getUserProfile(userId));
18→  if (!profile) return null;
19→
20→  const events = options.events ?? (await buildContributionEvents());
21→  const nextXp = computeCanonicalUserXp(events, userId);
22→  if ((profile.XP ?? 0) === nextXp) return profile;
23→
24→  const nextProfile: UserProfile = { ...profile, XP: nextXp };
25→  await upsertUserProfile(userId, nextProfile);
26→  return nextProfile;
27→}
