 3→type NavigatorWithConnection = Navigator & {
 4→  connection?: {
 5→    effectiveType?: string;
 6→    type?: string;
 7→  };
 8→};
 9→
10→async function collectMotionSignals(durationMs: number): Promise<{
11→  hasAccelerometerData: boolean;
12→  hasGyroscopeData: boolean;
13→  accelerometerSampleCount: number;
14→  motionDetectedDuringCapture: boolean;
15→}> {
16→  if (typeof window === "undefined" || typeof window.addEventListener !== "function") {
17→    return {
18→      hasAccelerometerData: false,
19→      hasGyroscopeData: false,
20→      accelerometerSampleCount: 0,
21→      motionDetectedDuringCapture: false,
22→    };
23→  }
24→
25→  return await new Promise((resolve) => {
26→    let accelerometerSampleCount = 0;
27→    let hasAccelerometerData = false;
28→    let hasGyroscopeData = false;
29→    let motionDetectedDuringCapture = false;
30→
31→    const onMotion = (event: DeviceMotionEvent) => {
32→      const acceleration = event.accelerationIncludingGravity ?? event.acceleration;
33→      const rotation = event.rotationRate;
34→      if (acceleration) {
35→        hasAccelerometerData = true;
36→        accelerometerSampleCount += 1;
37→        const magnitude = Math.abs(acceleration.x ?? 0) + Math.abs(acceleration.y ?? 0) + Math.abs(acceleration.z ?? 0);
38→        if (magnitude > 3) motionDetectedDuringCapture = true;
39→      }
40→      if (rotation && (rotation.alpha || rotation.beta || rotation.gamma)) {
41→        hasGyroscopeData = true;
42→      }
43→    };
44→
45→    window.addEventListener("devicemotion", onMotion);
46→    window.setTimeout(() => {
47→      window.removeEventListener("devicemotion", onMotion);
48→      resolve({
49→        hasAccelerometerData,
50→        hasGyroscopeData,
51→        accelerometerSampleCount,
52→        motionDetectedDuringCapture,
53→      });
54→    }, durationMs);
55→  });
56→}
57→
58→export async function collectGpsIntegrity(position: GeolocationPosition | null): Promise<GpsIntegrityReport> {
59→  const nav = navigator as NavigatorWithConnection;
60→  const coords = position?.coords as (GeolocationCoordinates & { isMocked?: boolean }) | undefined;
61→  const motion = await collectMotionSignals(600);
62→
63→  return {
64→    mockLocationDetected: coords?.isMocked === true,
65→    mockLocationMethod: coords?.isMocked === true ? "Position.isMocked" : null,
66→    hasAccelerometerData: motion.hasAccelerometerData,
67→    hasGyroscopeData: motion.hasGyroscopeData,
68→    accelerometerSampleCount: motion.accelerometerSampleCount,
69→    motionDetectedDuringCapture: motion.motionDetectedDuringCapture,
70→    gpsAccuracyMeters: typeof coords?.accuracy === "number" ? coords.accuracy : null,
71→    networkType: nav.connection?.effectiveType ?? nav.connection?.type ?? null,
72→    gpsTimestamp: typeof position?.timestamp === "number" ? position.timestamp : null,
73→    deviceTimestamp: Date.now(),
74→    timeDeltaMs: typeof position?.timestamp === "number" ? Math.abs(Date.now() - position.timestamp) : null,
75→  };
76→}
