 95→
 96→## 2. GPS Spoofing Detection
 97→
 98→### 2.1 Multi-Layered Detection Architecture
 99→
100→GPS spoofing is ADL's highest-priority fraud vector (Teammate 5's T4: risk score 16/25). The current system checks EXIF GPS against submission GPS (1km threshold) and IP geolocation (50km threshold), but this is insufficient. The following multi-layered system addresses the gaps.
101→
102→```
103→GPS SPOOFING DETECTION PIPELINE
104→================================
105→
106→Layer 1: CLIENT-SIDE CHECKS (in PWA before submission)
107→  ├── Mock location API detection
108→  ├── Sensor data consistency (accelerometer, gyroscope)
109→  ├── GPS accuracy metadata capture
110→  └── Network type recording
111→
112→Layer 2: SERVER-SIDE CHECKS (at submission time)
113→  ├── EXIF GPS vs submission GPS (existing, 1km threshold)
114→  ├── IP geolocation vs submission GPS (existing, 50km threshold)
115→  ├── Velocity analysis (impossible travel between submissions)
116→  ├── Cell tower / network type consistency
117→  └── Known location database cross-reference
118→
119→Layer 3: STATISTICAL ANALYSIS (batch, post-submission)
120→  ├── Agent movement pattern modeling
121→  ├── Impossible travel detection across sessions
122→  ├── GPS coordinate clustering analysis
123→  ├── Precision anomaly detection
124→  └── Collusion pattern detection
125→
126→Output: GPS Confidence Score (0-100)
127→```
128→
129→### 2.2 Layer 1: Client-Side Checks
130→
131→These checks run in the PWA before submission. They cannot prevent a determined attacker (client-side checks are bypassable) but they raise the bar and collect signals for server-side analysis.
132→
133→```typescript
134→// lib/client/gpsIntegrity.ts
135→
136→interface GpsIntegrityReport {
137→  // Mock location detection
138→  mockLocationDetected: boolean;
139→  mockLocationMethod: string | null;
140→
141→  // Sensor consistency
142→  hasAccelerometerData: boolean;
143→  hasGyroscopeData: boolean;
144→  accelerometerSampleCount: number;
145→  motionDetectedDuringCapture: boolean;
146→
147→  // GPS metadata
148→  gpsAccuracyMeters: number | null;
149→  gpsProvider: string | null;  // 'gps' | 'network' | 'fused' | 'unknown'
150→  gpsSatelliteCount: number | null;
151→  gpsAltitudeMeters: number | null;
152→  gpsSpeedMps: number | null;
153→  gpsHeading: number | null;
154→
155→  // Network context
156→  networkType: string | null;  // 'wifi' | '4g' | '3g' | '2g' | 'unknown'
157→  wifiSSID: string | null;     // if on wifi (may be null due to permissions)
158→
159→  // Timestamps
160→  gpsTimestamp: number;        // from Position.timestamp
161→  deviceTimestamp: number;     // Date.now() at capture
162→  timeDeltaMs: number;         // |gpsTimestamp - deviceTimestamp|
163→}
164→
165→async function collectGpsIntegrity(
166→  position: GeolocationPosition
167→): Promise<GpsIntegrityReport> {
168→  const report: GpsIntegrityReport = {
169→    mockLocationDetected: false,
170→    mockLocationMethod: null,
171→    hasAccelerometerData: false,
172→    hasGyroscopeData: false,
173→    accelerometerSampleCount: 0,
174→    motionDetectedDuringCapture: false,
175→    gpsAccuracyMeters: position.coords.accuracy ?? null,
176→    gpsProvider: null,
177→    gpsSatelliteCount: null,
178→    gpsAltitudeMeters: position.coords.altitude ?? null,
179→    gpsSpeedMps: position.coords.speed ?? null,
180→    gpsHeading: position.coords.heading ?? null,
181→    networkType: null,
182→    wifiSSID: null,
183→    gpsTimestamp: position.timestamp,
184→    deviceTimestamp: Date.now(),
185→    timeDeltaMs: Math.abs(Date.now() - position.timestamp),
186→  };
187→
188→  // ── MOCK LOCATION DETECTION ──
189→  // Android exposes Position.isMocked in some browsers (Chrome 90+)
190→  // This is the strongest client-side signal
191→  const coords = position.coords as GeolocationCoordinates & {
192→    isMocked?: boolean;
193→  };
194→  if (coords.isMocked === true) {
195→    report.mockLocationDetected = true;
196→    report.mockLocationMethod = 'Position.isMocked API';
197→  }
198→
199→  // Suspiciously perfect coordinates (exact to 6+ decimal places
200→  // with no trailing noise) suggest programmatic generation
201→  const latStr = position.coords.latitude.toString();
202→  const lonStr = position.coords.longitude.toString();
203→  const latDecimals = latStr.includes('.') ? latStr.split('.')[1].length : 0;
204→  const lonDecimals = lonStr.includes('.') ? lonStr.split('.')[1].length : 0;
205→  if (latDecimals <= 4 && lonDecimals <= 4 && position.coords.accuracy === 0) {
206→    report.mockLocationDetected = true;
207→    report.mockLocationMethod = 'Suspiciously low precision with zero accuracy';
208→  }
209→
210→  // GPS accuracy of exactly 0 or exactly 1 meter is unrealistic
211→  // for consumer Android phones (typical: 3-30m)
212→  if (position.coords.accuracy !== null &&
213→      position.coords.accuracy !== undefined &&
214→      position.coords.accuracy < 1) {
215→    report.mockLocationDetected = true;
216→    report.mockLocationMethod = 'Sub-meter accuracy on consumer device';
217→  }
218→
219→  // ── SENSOR DATA COLLECTION ──
220→  // Collect 2 seconds of accelerometer data to verify physical movement
221→  try {
222→    const sensorData = await collectSensorData(2000);
223→    report.hasAccelerometerData = sensorData.hasAccelerometer;
224→    report.hasGyroscopeData = sensorData.hasGyroscope;
225→    report.accelerometerSampleCount = sensorData.sampleCount;
226→    report.motionDetectedDuringCapture = sensorData.motionDetected;
227→  } catch {
228→    // Sensor API not available -- common on low-end phones
229→    // Not a fraud signal by itself
230→  }
231→
232→  // ── NETWORK TYPE ──
233→  const connection = (navigator as Navigator & {
234→    connection?: { effectiveType?: string; type?: string };
235→  }).connection;
236→  if (connection) {
237→    report.networkType = connection.effectiveType ?? connection.type ?? 'unknown';
238→  }
239→
240→  return report;
241→}
242→
243→interface SensorSample {
244→  x: number;
245→  y: number;
246→  z: number;
247→  timestamp: number;
248→}
249→
250→async function collectSensorData(durationMs: number): Promise<{
251→  hasAccelerometer: boolean;
252→  hasGyroscope: boolean;
253→  sampleCount: number;
254→  motionDetected: boolean;
255→}> {
256→  return new Promise((resolve) => {
257→    const samples: SensorSample[] = [];
258→    let hasAccel = false;
259→    let hasGyro = false;
260→
261→    const handler = (event: DeviceMotionEvent) => {
262→      if (event.accelerationIncludingGravity) {
263→        hasAccel = true;
264→        samples.push({
265→          x: event.accelerationIncludingGravity.x ?? 0,
266→          y: event.accelerationIncludingGravity.y ?? 0,
267→          z: event.accelerationIncludingGravity.z ?? 0,
268→          timestamp: Date.now(),
269→        });
270→      }
271→      if (event.rotationRate) {
272→        hasGyro = true;
273→      }
274→    };
275→
276→    window.addEventListener('devicemotion', handler);
277→
278→    setTimeout(() => {
279→      window.removeEventListener('devicemotion', handler);
280→
281→      // Motion detection: check if accelerometer values vary
282→      // A stationary spoofed device will show near-constant values
283→      // A device being carried shows natural micro-vibrations
284→      let motionDetected = false;
285→      if (samples.length >= 5) {
286→        const xValues = samples.map(s => s.x);
287→        const variance = computeVariance(xValues);
288→        // Walking produces variance > 0.1 m/s^2
289→        // A phone on a desk: variance ~0.01-0.05
290→        // Spoofed/emulator: variance ~0 or exactly constant
291→        motionDetected = variance > 0.05;
292→      }
293→
294→      resolve({
295→        hasAccelerometer: hasAccel,
296→        hasGyroscope: hasGyro,
297→        sampleCount: samples.length,
298→        motionDetected,
299→      });
300→    }, durationMs);
301→  });
302→}
303→
304→function computeVariance(values: number[]): number {
305→  if (values.length < 2) return 0;
306→  const mean = values.reduce((a, b) => a + b, 0) / values.length;
307→  const squaredDiffs = values.map(v => (v - mean) ** 2);
308→  return squaredDiffs.reduce((a, b) => a + b, 0) / (values.length - 1);
309→}
310→```
311→
312→### 2.3 Layer 2: Server-Side Checks
313→
314→```typescript
315→// lib/server/gpsValidation.ts
316→
317→interface GpsValidationResult {
318→  gpsConfidenceScore: number;  // 0-100
319→  flags: GpsFlag[];
320→  velocityCheckResult: 'ok' | 'flag' | 'block';
321→  ipMatchResult: 'match' | 'mismatch' | 'unknown';
322→  exifMatchResult: 'match' | 'mismatch' | 'no_exif';
323→  mockLocationResult: 'clean' | 'detected' | 'unknown';
324→}
325→
326→interface GpsFlag {
327→  rule: string;
328→  severity: 'info' | 'warning' | 'critical';
329→  detail: string;
330→}
331→
332→async function validateGps(params: {
333→  userId: string;
334→  submissionLocation: SubmissionLocation;
335→  submissionTime: Date;
336→  photoExifGps: SubmissionLocation | null;
337→  ipLocation: SubmissionLocation | null;
338→  clientGpsIntegrity: GpsIntegrityReport | null;
339→  isLowEndDevice: boolean;
340→}): Promise<GpsValidationResult> {
341→  const flags: GpsFlag[] = [];
342→  let score = 100;  // Start at 100, deduct for issues
343→
344→  // ── CHECK 1: Mock location from client report ──
345→  let mockLocationResult: 'clean' | 'detected' | 'unknown' = 'unknown';
346→  if (params.clientGpsIntegrity) {
347→    if (params.clientGpsIntegrity.mockLocationDetected) {
348→      mockLocationResult = 'detected';
349→      score -= 50;
350→      flags.push({
351→        rule: 'GPS_MOCK_DETECTED',
352→        severity: 'critical',
353→        detail: `Mock location detected via: ${params.clientGpsIntegrity.mockLocationMethod}`,
354→      });
355→    } else {
356→      mockLocationResult = 'clean';
357→    }
358→
359→    // GPS accuracy sanity check
360→    const accuracy = params.clientGpsIntegrity.gpsAccuracyMeters;
361→    if (accuracy !== null) {
362→      if (accuracy > 100 && !params.isLowEndDevice) {
363→        score -= 10;
364→        flags.push({
365→          rule: 'GPS_LOW_ACCURACY',
366→          severity: 'warning',
367→          detail: `GPS accuracy ${accuracy}m exceeds 100m threshold`,
368→        });
369→      }
370→      if (accuracy === 0) {
371→        score -= 20;
372→        flags.push({
373→          rule: 'GPS_ZERO_ACCURACY',
374→          severity: 'critical',
375→          detail: 'GPS accuracy reported as 0 -- likely spoofed',
376→        });
377→      }
378→    }
379→
380→    // GPS timestamp vs device timestamp divergence
381→    if (params.clientGpsIntegrity.timeDeltaMs > 30000) {
382→      score -= 10;
383→      flags.push({
384→        rule: 'GPS_TIME_DRIFT',
385→        severity: 'warning',
386→        detail: `GPS timestamp and device clock differ by ${Math.round(params.clientGpsIntegrity.timeDeltaMs / 1000)}s`,
387→      });
388→    }
389→
390→    // No sensor data on a modern device is suspicious
391→    if (!params.clientGpsIntegrity.hasAccelerometerData &&
392→        !params.isLowEndDevice) {
393→      score -= 5;
394→      flags.push({
395→        rule: 'GPS_NO_SENSORS',
396→        severity: 'info',
397→        detail: 'No accelerometer data available -- possible emulator',
398→      });
399→    }
400→

400→
401→    // No motion during capture
402→    if (params.clientGpsIntegrity.hasAccelerometerData &&
403→        !params.clientGpsIntegrity.motionDetectedDuringCapture &&
404→        params.clientGpsIntegrity.accelerometerSampleCount >= 10) {
405→      score -= 5;
406→      flags.push({
407→        rule: 'GPS_NO_MOTION',
408→        severity: 'info',
409→        detail: 'No physical motion detected during GPS capture',
410→      });
411→    }
412→  } else {
413→    // No GPS integrity report at all
414→    score -= 5;
415→  }
416→
417→  // ── CHECK 2: EXIF GPS cross-validation (existing logic, extended) ──
418→  let exifMatchResult: 'match' | 'mismatch' | 'no_exif' = 'no_exif';
419→  if (params.photoExifGps) {
420→    const threshold = params.isLowEndDevice ? 2.0 : 1.0; // km
421→    const dist = haversineKm(params.submissionLocation, params.photoExifGps);
422→    if (dist <= threshold) {
423→      exifMatchResult = 'match';
424→      // Bonus for matching
425→      score = Math.min(100, score + 5);
426→    } else {
427→      exifMatchResult = 'mismatch';
428→      score -= 30;
429→      flags.push({
430→        rule: 'GPS_EXIF_MISMATCH',
431→        severity: 'critical',
432→        detail: `Photo EXIF GPS is ${dist.toFixed(2)}km from submission GPS (threshold: ${threshold}km)`,
433→      });
434→    }
435→  } else {
436→    // No EXIF GPS -- penalize but less for low-end devices
437→    score -= params.isLowEndDevice ? 5 : 15;
438→    flags.push({
439→      rule: 'GPS_NO_EXIF',
440→      severity: params.isLowEndDevice ? 'info' : 'warning',
441→      detail: 'Photo has no EXIF GPS data',
442→    });
443→  }
444→
445→  // ── CHECK 3: IP geolocation cross-validation ──
446→  let ipMatchResult: 'match' | 'mismatch' | 'unknown' = 'unknown';
447→  if (params.ipLocation) {
448→    const ipDist = haversineKm(params.ipLocation, params.submissionLocation);
449→    if (ipDist <= 50) {
450→      ipMatchResult = 'match';
451→    } else {
452→      ipMatchResult = 'mismatch';
453→      score -= 15;
454→      flags.push({
455→        rule: 'GPS_IP_MISMATCH',
456→        severity: 'warning',
457→        detail: `IP geolocates ${ipDist.toFixed(0)}km from submission GPS`,
458→      });
459→    }
460→  }
461→
462→  // ── CHECK 4: Velocity / impossible travel ──
463→  const velocityResult = await checkVelocity(
464→    params.userId,
465→    params.submissionLocation,
466→    params.submissionTime
467→  );
468→  if (velocityResult === 'block') {
469→    score -= 40;
470→    flags.push({
471→      rule: 'GPS_IMPOSSIBLE_TRAVEL',
472→      severity: 'critical',
473→      detail: 'Physically impossible speed between consecutive submissions',
474→    });
475→  } else if (velocityResult === 'flag') {
476→    score -= 15;
477→    flags.push({
478→      rule: 'GPS_HIGH_VELOCITY',
479→      severity: 'warning',
480→      detail: 'Unusually high speed between consecutive submissions',
481→    });
482→  }
483→
484→  return {
485→    gpsConfidenceScore: Math.max(0, Math.min(100, score)),
486→    flags,
487→    velocityCheckResult: velocityResult,
488→    ipMatchResult,
489→    exifMatchResult,
490→    mockLocationResult,
491→  };
492→}
493→
494→// Velocity check with Douala-specific thresholds
495→async function checkVelocity(
496→  userId: string,
497→  currentLocation: SubmissionLocation,
498→  currentTime: Date
499→): Promise<'ok' | 'flag' | 'block'> {
500→  // Fetch the user's last 5 submissions ordered by time
501→  const recentSubmissions = await getRecentSubmissionsByUser(userId, 5);
502→  if (recentSubmissions.length === 0) return 'ok';
503→
504→  const last = recentSubmissions[0];
505→  const distKm = haversineKm(last.location, currentLocation);
506→  const timeHours = (currentTime.getTime() - new Date(last.createdAt).getTime()) / 3600000;
507→
508→  if (timeHours <= 0 && distKm > 0.05) return 'block';
509→  if (timeHours <= 0) return 'ok';
510→
511→  const speedKmh = distKm / timeHours;
512→
513→  // Douala speed thresholds:
514→  //   Walking: ~5 km/h
515→  //   Moto-taxi in traffic: ~20-30 km/h
516→  //   Car on highway: ~60-80 km/h
517→  //   Maximum reasonable in Douala: 80 km/h (traffic is severe)
518→  //   Physically impossible: >200 km/h (no highway, no rail)
519→  if (speedKmh > 200) return 'block';
520→  if (speedKmh > 80) return 'flag';
521→
522→  // Also check: >5km apart within 2 minutes
523→  if (distKm > 5 && timeHours < (2 / 60)) return 'block';
524→
525→  return 'ok';
526→}
527→```
528→
529→### 2.4 Layer 3: Statistical Anomaly Detection (Batch)
530→
531→```typescript
532→// lib/server/gpsAnomalyDetection.ts
533→// Runs as a scheduled job (daily via Vercel Cron)
534→
535→interface AgentMovementProfile {
536→  userId: string;
537→  totalSubmissions: number;
538→  uniqueLocations: number;
539→  averageDistanceBetweenSubmissionsKm: number;
540→  maxDistanceBetweenConsecutiveSubmissionsKm: number;
541→  averageSpeedKmh: number;
542→  maxSpeedKmh: number;
543→  clusterCount: number;           // Number of distinct location clusters
544→  primaryClusterCentroid: SubmissionLocation | null;
545→  submissionRadiusKm: number;     // 95th percentile distance from centroid
546→  precisionDistribution: {
547→    exactFourDecimals: number;    // Suspiciously round coordinates
548→    fiveOrMoreDecimals: number;   // Normal GPS precision
549→  };
550→  anomalyFlags: string[];
551→}
552→
553→async function analyzeAgentMovementPatterns(
554→  userId: string,
555→  windowDays: number = 30
556→): Promise<AgentMovementProfile> {
557→  const submissions = await getSubmissionsByUserInWindow(userId, windowDays);
558→  const profile: AgentMovementProfile = {
559→    userId,
560→    totalSubmissions: submissions.length,
561→    uniqueLocations: 0,
562→    averageDistanceBetweenSubmissionsKm: 0,
563→    maxDistanceBetweenConsecutiveSubmissionsKm: 0,
564→    averageSpeedKmh: 0,
565→    maxSpeedKmh: 0,
566→    clusterCount: 0,
567→    primaryClusterCentroid: null,
568→    submissionRadiusKm: 0,
569→    precisionDistribution: { exactFourDecimals: 0, fiveOrMoreDecimals: 0 },
570→    anomalyFlags: [],
571→  };
572→
573→  if (submissions.length < 3) return profile;
574→
575→  // ── COORDINATE PRECISION ANALYSIS ──
576→  // Spoofing apps often generate coordinates with suspiciously
577→  // uniform precision (e.g., always exactly 6 decimal places)
578→  // or suspiciously round values (4 decimal places = ~11m precision)
579→  for (const sub of submissions) {
580→    const latStr = sub.latitude.toString();
581→    const lonStr = sub.longitude.toString();
582→    const latDecimals = latStr.includes('.') ? latStr.split('.')[1].replace(/0+$/, '').length : 0;
583→    const lonDecimals = lonStr.includes('.') ? lonStr.split('.')[1].replace(/0+$/, '').length : 0;
584→    if (latDecimals <= 4 && lonDecimals <= 4) {
585→      profile.precisionDistribution.exactFourDecimals++;
586→    } else {
587→      profile.precisionDistribution.fiveOrMoreDecimals++;
588→    }
589→  }
590→
591→  // Flag: >80% of coordinates have suspiciously low precision
592→  const lowPrecisionRatio = profile.precisionDistribution.exactFourDecimals / submissions.length;
593→  if (lowPrecisionRatio > 0.8 && submissions.length >= 10) {
594→    profile.anomalyFlags.push('PRECISION_ANOMALY: >80% of GPS coordinates have <=4 decimal places');
595→  }
596→
597→  // ── CONSECUTIVE DISTANCE AND SPEED ANALYSIS ──
598→  const sortedByTime = [...submissions].sort(
599→    (a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()
600→  );
601→
602→  const distances: number[] = [];
603→  const speeds: number[] = [];
604→
605→  for (let i = 1; i < sortedByTime.length; i++) {
606→    const dist = haversineKm(
607→      { latitude: sortedByTime[i - 1].latitude, longitude: sortedByTime[i - 1].longitude },
608→      { latitude: sortedByTime[i].latitude, longitude: sortedByTime[i].longitude }
609→    );
610→    distances.push(dist);
611→
612→    const timeH = (new Date(sortedByTime[i].createdAt).getTime() -
613→                   new Date(sortedByTime[i - 1].createdAt).getTime()) / 3600000;
614→    if (timeH > 0) {
615→      speeds.push(dist / timeH);
616→    }
617→  }
618→
619→  profile.averageDistanceBetweenSubmissionsKm =
620→    distances.reduce((a, b) => a + b, 0) / distances.length;
621→  profile.maxDistanceBetweenConsecutiveSubmissionsKm = Math.max(...distances);
622→
623→  if (speeds.length > 0) {
624→    profile.averageSpeedKmh = speeds.reduce((a, b) => a + b, 0) / speeds.length;
625→    profile.maxSpeedKmh = Math.max(...speeds);
626→  }
627→
628→  // Flag: impossible max speed
629→  if (profile.maxSpeedKmh > 200) {
630→    profile.anomalyFlags.push(
631→      `IMPOSSIBLE_TRAVEL: Max speed ${profile.maxSpeedKmh.toFixed(0)} km/h`
632→    );
633→  }
634→
635→  // ── LOCATION CLUSTERING (Simple DBSCAN-like) ──
636→  // Cluster submissions within 200m of each other
637→  const clusters = clusterLocations(
638→    sortedByTime.map(s => ({ latitude: s.latitude, longitude: s.longitude })),
639→    0.2 // 200m cluster radius in km
640→  );
641→  profile.clusterCount = clusters.length;
642→
643→  // Unique locations: clusters + unclustered points
644→  const uniqueSet = new Set(
645→    sortedByTime.map(s => `${s.latitude.toFixed(5)},${s.longitude.toFixed(5)}`)
646→  );
647→  profile.uniqueLocations = uniqueSet.size;
648→
649→  // Flag: very few unique locations relative to submissions
650→  if (submissions.length >= 10 && profile.uniqueLocations < submissions.length * 0.3) {
651→    profile.anomalyFlags.push(
652→      `LOW_LOCATION_DIVERSITY: ${profile.uniqueLocations} unique locations for ${submissions.length} submissions`
653→    );
654→  }
655→
656→  // Primary cluster centroid
657→  if (clusters.length > 0) {
658→    const largest = clusters.sort((a, b) => b.length - a.length)[0];
659→    profile.primaryClusterCentroid = {
660→      latitude: largest.reduce((sum, p) => sum + p.latitude, 0) / largest.length,
661→      longitude: largest.reduce((sum, p) => sum + p.longitude, 0) / largest.length,
662→    };
663→  }
664→
665→  return profile;
666→}
667→
668→// Simple clustering: group points within radiusKm of each other
669→function clusterLocations(
670→  points: SubmissionLocation[],
671→  radiusKm: number
672→): SubmissionLocation[][] {
673→  const visited = new Set<number>();
674→  const clusters: SubmissionLocation[][] = [];
675→
676→  for (let i = 0; i < points.length; i++) {
677→    if (visited.has(i)) continue;
678→    visited.add(i);
679→    const cluster: SubmissionLocation[] = [points[i]];
680→
681→    for (let j = i + 1; j < points.length; j++) {
682→      if (visited.has(j)) continue;
683→      if (haversineKm(points[i], points[j]) <= radiusKm) {
684→        visited.add(j);
685→        cluster.push(points[j]);
686→      }
687→    }
688→
689→    if (cluster.length >= 2) {
690→      clusters.push(cluster);
691→    }
692→  }
693→
694→  return clusters;
695→}
