220→   220→function groupEventsByPoint(items: AdminSubmissionEvent[], language: 'en' | 'fr'): GroupedPoint[] {
221→   221→  const groups = new Map<string, AdminSubmissionEvent[]>();
222→   222→  for (const item of items) {
223→   223→    const pid = item.event.pointId;
224→   224→    const existing = groups.get(pid);
225→   225→    if (existing) {
226→   226→      existing.push(item);
227→   227→    } else {
228→   228→      groups.set(pid, [item]);
229→   229→    }
230→   230→  }
231→   231→  const result: GroupedPoint[] = [];
232→   232→  for (const [pointId, events] of groups) {
233→   233→    const sorted = [...events].sort((a, b) => new Date(a.event.createdAt).getTime() - new Date(b.event.createdAt).getTime());
234→   234→    const latestEvent = sorted[sorted.length - 1]!;
235→   235→    const createdEvent = sorted.find((e) => e.event.eventType === 'CREATE_EVENT') ?? null;
236→   236→    const enrichEvents = sorted.filter((e) => e.event.eventType === 'ENRICH_EVENT');
237→   237→    const allPhotos: GroupedPoint['allPhotos'] = [];
238→   238→    for (const ev of sorted) {
239→   239→      const photoUrl = ev.event.photoUrl;
240→   240→      if (photoUrl && typeof photoUrl === 'string' && photoUrl.trim()) {
241→   241→        allPhotos.push({
242→   242→          url: photoUrl,
243→   243→          eventType: ev.event.eventType,
244→   244→          createdAt: ev.event.createdAt,
245→   245→          metadata: ev.fraudCheck?.primaryPhoto ?? null,
246→   246→        });
247→   247→      }
248→   248→      const details = ev.event.details as SubmissionDetails;
249→   249→      const secondUrl = typeof details.secondPhotoUrl === 'string' && details.secondPhotoUrl.trim() ? details.secondPhotoUrl : null;
250→   250→      if (secondUrl) {
251→   251→        allPhotos.push({
252→   252→          url: secondUrl,
253→   253→          eventType: ev.event.eventType + ' (secondary)',
254→   254→          createdAt: ev.event.createdAt,
255→   255→          metadata: ev.fraudCheck?.secondaryPhoto ?? null,
256→   256→        });
257→   257→      }
258→   258→    }
259→   259→    result.push({
260→   260→      pointId,
261→   261→      events: sorted,
262→   262→      category: latestEvent.event.category,
263→   263→      siteName: getSiteName(createdEvent ?? latestEvent, language),
264→   264→      latestEvent,
265→   265→      createdEvent,
266→   266→      enrichEvents,
267→   267→      allPhotos,
268→   268→    });
269→   269→  }
270→   270→  return result.sort((a, b) => new Date(b.latestEvent.event.createdAt).getTime() - new Date(a.latestEvent.event.createdAt).getTime());
271→   271→}
